1	export type Item = {
2	  type: string;
3	};
4	
5	export type QuoteStep = {
6	  op: "quote";
7	  items: Item[];
8	};
9	
10	export type Step = QuoteStep;
11	
12	export type Scenario = {
13	  customer: { yearsWithMHPCO: number };
14	  steps: Step[];
15	};
16	
17	export type QuoteResult = { premium: number };
18	export type StepResult = QuoteResult;
19	export type ScenarioResult = { results: StepResult[] };
20	
21	const PROCESSING_FEE = 5;
22	
23	const BASE_PREMIUMS: Record<string, number> = {
24	  sword: 100,
25	};
26	
27	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
28	
29	const quotePremium = (items: Item[]): number => {
30	  const itemsBase = items.reduce((sum, item) => sum + itemBasePremium(item), 0);
31	  const firstInsurance = itemsBase * 0.1;
32	  return Math.ceil(itemsBase + firstInsurance + PROCESSING_FEE);
33	};
34	
35	export const runScenario = (scenario: Scenario): ScenarioResult => {
36	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
37	  return { results };
38	};
